mapper.select:
SELECT o.order_id AS orderId, i.goods_name AS goodsName, i.goods_img AS goodsImg, i.sku_spec AS skuSpec, i.per_price AS perPrice, i.buy_num AS buyNum, o.price AS payAmount, o.order_status AS status FROM user_order o INNER JOIN user_order_item i ON o.order_id = i.order_id WHERE o.user_id = #{userId}
AND o.order_status = #{status}
ORDER BY o.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT o.order_id AS orderId, i.goods_name AS goodsName, i.goods_img AS goodsImg, i.sku_spec AS skuSpec, i.per_price AS perPrice, i.buy_num AS buyNum, o.price AS payAmount, o.order_status AS status FROM user_order o INNER JOIN user_order_item i ON o.order_id = i.order_id WHERE o.shop_id = #{shopId}
AND o.order_status = #{status}
ORDER BY o.create_time DESC LIMIT #{offset}, #{pageSize}

select
    uoi.sku_spec
from user_order uo
    inner join user_order_item uoi on uoi.order_id=uo.order_id
where uo.order_id = #{orderId}
  and uo.user_id = #{userId}
  and uoi.spu_id = #{spuId}
  and uoi.sku_id = #{skuId}
